import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

// Função para converter snake_case/camelCase para uma legenda mais amigável em português
function formatLabel(label) {
  // Se já estiver traduzido em um dicionário, use-o (você pode expandir isso)
  const dictionary = {
    nome: "Nome",
    ra: "RA",
    usuario: "Usuário",
    role: "Perfil",
    periodo_nome: "Período",
    periodo_turno: "Turno",
    pin: "PIN",
    cpf: "CPF",
    rg: "RG",
    telefone: "Telefone",
    numero_prontuario: "Nº Prontuário",
    numero_gaveta: "Nº Gaveta",
    cidade: "Cidade",
    endereco: "Endereço",
    numero: "Nº",
    data_nascimento: "Nascimento",
    idade: "Idade",
    observacao: "Obs"
  };
  if (dictionary[label]) return dictionary[label];

  // Se não, transforma snake_case/camelCase em palavras separadas e capitaliza
  return label
    .replace(/([A-Z])/g, " $1") // camelCase para palavras separadas
    .replace(/_/g, " ")         // snake_case para palavras separadas
    .replace(/\b\w/g, l => l.toUpperCase());
}

export default function TelaLogs() {
  const { user } = useAuth();
  const [logs, setLogs] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [erro, setErro] = useState(null);
  const [filtros, setFiltros] = useState({
    usuario: "",
    acao: "",
    entidade: "",
    texto: ""
  });

  // Buscar logs
  useEffect(() => {
    const fetchLogs = async () => {
      setCarregando(true);
      setErro(null);
      try {
        const res = await axios.get("/api/logs", {
          headers: { Authorization: `Bearer ${user.token}` }
        });
        setLogs(res.data);
      } catch (err) {
        setErro("Erro ao carregar logs");
      } finally {
        setCarregando(false);
      }
    };
    fetchLogs();
  }, [user.token]);

  // Gerar listas únicas para filtros dropdown
  const usuarios = Array.from(new Set(logs.map(l => l.usuario_nome).filter(Boolean)));
  const entidades = Array.from(new Set(logs.map(l => l.entidade).filter(Boolean)));
  const acoes = Array.from(new Set(logs.map(l => l.acao).filter(Boolean)));

  // Filtro dinâmico
  const logsFiltrados = logs.filter((l) => {
    const { usuario, acao, entidade, texto } = filtros;
    return (
      (!usuario || l.usuario_nome === usuario) &&
      (!acao || l.acao === acao) &&
      (!entidade || l.entidade === entidade) &&
      (!texto ||
        (l.usuario_nome?.toLowerCase().includes(texto.toLowerCase()) ||
         l.detalhes?.toLowerCase().includes(texto.toLowerCase()) ||
         l.entidade?.toLowerCase().includes(texto.toLowerCase()) ||
         l.acao?.toLowerCase().includes(texto.toLowerCase()))
      )
    );
  });

  // Função para exibir detalhes amigáveis automaticamente
  function renderDetalhes(log) {
    if (!log.detalhes || log.detalhes === "{}") return <span>-</span>;
    let data;
    try {
      data = typeof log.detalhes === "string" ? JSON.parse(log.detalhes) : log.detalhes;
    } catch {
      return <span>{log.detalhes}</span>;
    }
    // Cria o array formatado
    const campos = Object.entries(data)
      .filter(([_, v]) => v !== undefined && v !== "")
      .map(([k, v]) => `${formatLabel(k)}: ${v === null ? "--" : v}`);

    if (campos.length === 0) return <span>-</span>;
    return <span>{campos.join(", ")}</span>;
  }

  return (
    <div className="max-w-6xl mx-auto mt-10 p-6 bg-white rounded-2xl shadow-2xl">
      <h2 className="text-2xl font-bold mb-4 text-[#23263A]">Auditoria do Sistema</h2>

      {/* FILTROS */}
      <div className="flex flex-wrap gap-4 mb-4">
        <select
          className="border rounded px-3 py-2"
          value={filtros.usuario}
          onChange={e => setFiltros(f => ({ ...f, usuario: e.target.value }))}
        >
          <option value="">Todos os usuários</option>
          {usuarios.map(u => <option key={u} value={u}>{u}</option>)}
        </select>
        <select
          className="border rounded px-3 py-2"
          value={filtros.acao}
          onChange={e => setFiltros(f => ({ ...f, acao: e.target.value }))}
        >
          <option value="">Todas as ações</option>
          {acoes.map(a => <option key={a} value={a}>{a.charAt(0).toUpperCase() + a.slice(1)}</option>)}
        </select>
        <select
          className="border rounded px-3 py-2"
          value={filtros.entidade}
          onChange={e => setFiltros(f => ({ ...f, entidade: e.target.value }))}
        >
          <option value="">Todas as entidades</option>
          {entidades.map(ent => <option key={ent} value={ent}>{ent.charAt(0).toUpperCase() + ent.slice(1)}</option>)}
        </select>
        <input
          type="text"
          placeholder="Buscar em qualquer campo..."
          className="border rounded px-3 py-2 w-72"
          value={filtros.texto}
          onChange={e => setFiltros(f => ({ ...f, texto: e.target.value }))}
        />
      </div>

      <div className="overflow-x-auto rounded-2xl border">
        <table className="min-w-full text-sm">
          <thead className="bg-gray-100 text-gray-600 font-semibold">
            <tr>
              <th className="px-4 py-3 text-left">Data/Hora</th>
              <th className="px-4 py-3 text-left">Usuário</th>
              <th className="px-4 py-3 text-left">Ação</th>
              <th className="px-4 py-3 text-left">Entidade</th>
              <th className="px-4 py-3 text-left">ID</th>
              <th className="px-4 py-3 text-left">Detalhes</th>
            </tr>
          </thead>
          <tbody>
            {logsFiltrados.length === 0 && (
              <tr>
                <td colSpan={6} className="text-center py-8 text-gray-400">
                  Nenhum registro encontrado.
                </td>
              </tr>
            )}
            {logsFiltrados.map((log) => (
              <tr key={log.id} className="border-t hover:bg-gray-50">
                <td className="px-4 py-2 whitespace-nowrap">{new Date(log.criado_em).toLocaleString()}</td>
                <td className="px-4 py-2">{log.usuario_nome}</td>
                <td className="px-4 py-2 capitalize">{log.acao}</td>
                <td className="px-4 py-2">{log.entidade}</td>
                <td className="px-4 py-2">{log.entidade_id}</td>
                <td className="px-4 py-2">{renderDetalhes(log)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
